function solve(points: number[][]): number {
    const MOD = 10**9 + 7;
    const inv2 = 500000004; // Modular inverse of 2 under MOD

    const yCount = new Map<number, number>();
    for (const [x, y] of points) {
        const cnt = yCount.get(y) || 0;
        yCount.set(y, cnt + 1);
    }

    let S = 0;
    let T = 0;
    for (const cnt of yCount.values()) {
        const c = cnt * (cnt - 1) / 2;
        S = (S + c) % MOD;
        T = (T + c * c) % MOD;
    }

    const numerator = (S * S - T + MOD) % MOD;
    const ans = (numerator * inv2) % MOD;
    return ans;
}

